//
//  TrackMapViewControllerBridge.swift
//  Radiacode
//
//  Created by Matvey Kozin on 25.10.2023.
//

import GoogleMaps
import SwiftUI

struct TrackMapViewControllerBridge: UIViewControllerRepresentable {

    enum StartPosition {
        case userLocation
        case markers
    }

    enum Consts {
        static let defaultZoomLevel: Float = 16
    }

    private var markers: Set<TrackMarker>
    @Binding var selectedMarker: TrackMarker?
    @Binding var navigateToMyLocation: Bool
    @Binding private var valuesOption: TrackScreenOptions.Values
    let startPosition: StartPosition

    init(
        markers: Set<TrackMarker>?,
        selectedMarker: Binding<TrackMarker?>? = nil,
        navigateToMyLocation: Binding<Bool>,
        valuesOption: Binding<TrackScreenOptions.Values>? = nil,
        startPosition: StartPosition = .userLocation
    ) {
        self.markers = markers ?? .init()
        self._selectedMarker = selectedMarker ?? .constant(nil)
        self._navigateToMyLocation = navigateToMyLocation
        self._valuesOption = valuesOption ?? .constant(.count)
        self.startPosition = startPosition
    }

    func makeUIViewController(context: Context) -> TrackMapViewController {
        let startPosition: TrackMapViewController.StartPosition
        switch self.startPosition {
        case .userLocation:
            startPosition = .userLocation
        case .markers:
            var bounds = GMSCoordinateBounds()
            for coordinate in markers {
                bounds = bounds.includingCoordinate(coordinate.coordinate)
            }
            startPosition = .markers(bounds)
        }

        return TrackMapViewController(startPostion: startPosition, delegate: context.coordinator)
    }

    @MainActor
    func updateUIViewController(_ uiViewController: TrackMapViewController, context: Context) {

        if context.coordinator.mapView == nil {
            context.coordinator.mapView = uiViewController.map
        }

        if markers != context.coordinator.cachedMarkers {
            context.coordinator.cachedMarkers = markers
        }

        if valuesOption != context.coordinator.cachedValuesOption {
            context.coordinator.cachedValuesOption = valuesOption
        }

        if selectedMarker != context.coordinator.cachedSelectedMarker {
            context.coordinator.cachedSelectedMarker = selectedMarker
        }

        if navigateToMyLocation {
            if let coordinate = uiViewController.map.myLocation?.coordinate {
                uiViewController.map.animate(to: GMSCameraPosition.camera(withTarget: coordinate, zoom: Consts.defaultZoomLevel))
            }
        }
    }

    static func dismantleUIViewController(_ uiViewController: TrackMapViewController, coordinator: MapViewCoordinator) {
        uiViewController.map.delegate = nil
        coordinator.invalidate()
        coordinator.clearMap()
    }

    func makeCoordinator() -> MapViewCoordinator {
        return MapViewCoordinator(self)
    }
}

