//
//  MapViewCoordinator.swift
//  Radiacode
//
//  Created by Matvey Kozin on 21.12.2023.
//

import Foundation
import GoogleMaps
import Combine

extension TrackMapViewControllerBridge {

    final class MapViewCoordinator: NSObject, GMSMapViewDelegate {

        typealias GMSTrackMarkerConsts = TrackMapViewControllerBridge.MapViewCoordinator.GMSTrackMarker.Consts

        private var maxMarkerValue: Float?
        private var minMarkerValue: Float?
        private var mapMarkers: Set<GMSTrackMarker> = []
        private var mapViewControllerBridge: TrackMapViewControllerBridge
        private var mapValues: [Int: Int] = [:]
        private var task: Task<Void, Never>?
        private var isBridgeValid = true

        weak var mapView: GMSMapView?

        var cachedValuesOption: TrackScreenOptions.Values = .count {
            didSet {
                if oldValue != cachedValuesOption {
                    task?.cancel()
                    task = Task { [weak self] in
                        guard let self else { return }
                        await self.recalculateDots()
                    }
                }
            }
        }

        var cachedSelectedMarker: TrackMarker? {
            didSet {
                if let oldValue, let marker = mapMarkers.first(where: { $0.timestamp == oldValue.timestamp }) {
                    marker.isSelected = false
                }
            }
        }

        var cachedMarkers: Set<TrackMarker> = [] {
            didSet {
                if cachedMarkers.isEmpty {
                    clearMap()
                } else if oldValue.isEmpty {
                    /// Начальная установка точек
                    calculateDots()
                    task?.cancel()
                    task = Task { [weak self] in
                        guard let self else { return }
                        await createMapMarkers(cachedMarkers, animation: cachedMarkers.count == 1 ? .pop : .none)
                    }
                } else if oldValue.count > cachedMarkers.count {
                    /// Удаленные точки
                    let removedObjects = oldValue.subtracting(cachedMarkers)
                    if !removedObjects.isEmpty {
                        task?.cancel()
                        task = Task { [weak self] in
                            guard let self else { return }
                            /// Определение был ли удален максимальный или минимальный маркер
                            if let minMarkerValue, let maxMarkerValue {
                                let removedValues = removedObjects.nonEmptyValues(type: cachedValuesOption)
                                if removedValues.contains(minMarkerValue) || removedValues.contains(maxMarkerValue) {
                                    await recalculateDots()
                                } else {
                                    removedObjects.forEach {
                                        self.mapValues.removeValue(forKey: $0.timestamp)
                                    }
                                }
                            } else {
                                await recalculateDots()
                            }
                            await removeMarkers(removedObjects)
                        }
                    }
                } else if oldValue.count < cachedMarkers.count {
                    /// Новые точки
                    let addedObjects = cachedMarkers.subtracting(oldValue)
                    if !addedObjects.isEmpty {
                        task?.cancel()
                        task = Task { [weak self] in
                            guard let self else { return }
                            if let minMarkerValue, let maxMarkerValue {
                                let addedValues = addedObjects.nonEmptyValues(type: cachedValuesOption)
                                if let maxCandidate = addedValues.max(), let minCandidate = addedValues.min(), maxCandidate > maxMarkerValue || minCandidate < minMarkerValue {
                                    await recalculateDots()
                                } else {
                                    fillMapValues(markers: addedObjects, maxValue: maxMarkerValue, minValue: minMarkerValue)
                                }
                            } else {
                                await recalculateDots()
                            }
                            await createMapMarkers(addedObjects, animation: .pop)
                        }
                    }
                } else {
                    /// Обновленные значения точек
                    let updatedMarkers = cachedMarkers.symmetricDifference(oldValue)
                    if !updatedMarkers.isEmpty {
                        task?.cancel()
                        task = Task { [weak self] in
                            guard let self else { return }
                            if let minMarkerValue, let maxMarkerValue {
                                let updatedValues = updatedMarkers.map({ self.cachedValuesOption == .dose ? $0.doseRate : $0.countRate })
                                if let maxCandidate = updatedValues.max(), let minCandidate = updatedValues.min(), maxCandidate > maxMarkerValue || minCandidate < minMarkerValue {
                                    await recalculateDots()
                                } else {
                                    fillMapValues(markers: updatedMarkers, maxValue: maxMarkerValue, minValue: minMarkerValue)
                                }
                            } else {
                                await recalculateDots()
                            }
                        }
                    }
                }
            }
        }

        init(_ mapViewControllerBridge: TrackMapViewControllerBridge) {
            self.mapViewControllerBridge = mapViewControllerBridge
        }

        /// Очистка карты
        func clearMap() {
            mapView?.clear()
            maxMarkerValue = nil
            minMarkerValue = nil
            mapValues = [:]
            mapMarkers = .init()
            cachedSelectedMarker = nil
        }

        @MainActor
        private func createMapMarkers(_ markers: Set<TrackMarker>, animation: GMSMarkerAnimation) async {
            for trackMarker in markers {
                guard !Task.isCancelled else { return }
                guard let colorHueValue = self.mapValues[trackMarker.timestamp] else { return }
                let marker = GMSTrackMarker(timestamp: trackMarker.timestamp, position: trackMarker.coordinate)
                marker.groundAnchor = CGPoint(x: 0.4, y: 0.4)
                marker.appearAnimation = animation
                marker.tracksViewChanges = false
                marker.tracksInfoWindowChanges = false
                marker.colorHue = colorHueValue
                marker.map = self.mapView
                self.mapMarkers.insert(marker)
            }
        }

        @MainActor
        private func removeMarkers(_ markers: Set<TrackMarker>) {
            markers.forEach { trackMarker in
                if let marker = mapMarkers.first(where: { $0.timestamp == trackMarker.timestamp }) {
                    mapMarkers.remove(marker)
                    marker.map = nil
                }
            }
        }

        private func recalculateDots() async {
            calculateDots()
            await updateCurrentDots()
        }

        @MainActor
        private func updateCurrentDots() async {
            mapMarkers.forEach { marker in
                guard !Task.isCancelled else { return }
                guard let colorHueValue = mapValues[marker.timestamp] else { return }
                marker.colorHue = colorHueValue
            }
        }

        private func calculateDots() {
            let filtredValues = cachedMarkers.nonEmptyValues(type: cachedValuesOption)
            guard let maxValue = filtredValues.max(), let minValue = filtredValues.min(), minValue != maxValue else {
                mapValues = cachedMarkers.reduce(into: [Int: Int]()) {
                    $0[$1.timestamp] = $1.isEmpty ? -1 : GMSTrackMarkerConsts.maxColorValue
                }
                return
            }
            self.maxMarkerValue = maxValue
            self.minMarkerValue = minValue

            mapValues.removeAll()
            fillMapValues(markers: cachedMarkers, maxValue: maxValue, minValue: minValue)
        }

        private func fillMapValues(markers: Set<TrackMarker>, maxValue: Float, minValue: Float) {
            let valueRange = maxValue - minValue
            let maxDefaultValue = Float(GMSTrackMarkerConsts.maxColorValue)

            markers.forEach { marker in
                let value: Int
                if marker.isEmpty {
                    value = -1
                } else {
                    let markerValue = self.cachedValuesOption == .dose ? marker.doseRate : marker.countRate
                    let colorValue = maxDefaultValue - (markerValue - minValue) / (valueRange) * maxDefaultValue
                    value = Int(colorValue)
                }
                mapValues[marker.timestamp] = value
            }
        }

        func mapView(_ mapView: GMSMapView, idleAt position: GMSCameraPosition) {
            guard isBridgeValid else { return }

            if mapViewControllerBridge.startPosition == .markers {
                if mapView.maxZoom == Consts.defaultZoomLevel {
                    mapView.setMinZoom(2, maxZoom: 21)
                }
            }

            if let coordinate = mapView.myLocation?.coordinate,
               Double.equal(coordinate.latitude, position.target.latitude, precise: 1),
               Double.equal(coordinate.longitude, position.target.longitude, precise: 1) {
                mapViewControllerBridge.navigateToMyLocation = false
            }
        }

        func mapView(_ mapView: GMSMapView, didTap marker: GMSMarker) -> Bool {
            guard isBridgeValid else { return false }

            if let marker = marker as? GMSTrackMarker, !marker.isSelected {
                marker.isSelected = true
                mapViewControllerBridge.selectedMarker = cachedMarkers.first(where: { $0.timestamp == marker.timestamp })
                mapView.animate(with: GMSCameraUpdate.setTarget(marker.position))
            }
            return false
        }

        func invalidate() {
            isBridgeValid = false
            task?.cancel()
        }

        deinit {
            task?.cancel()
        }
    }
}

private extension Set where Element == TrackMarker {

    func nonEmptyValues(type: TrackScreenOptions.Values) -> [Float] {
        if type == .dose {
            return compactMap { marker in
                guard !marker.isEmpty else { return nil }
                return marker.doseRate
            }
        } else {
            return compactMap { marker in
                guard !marker.isEmpty else { return nil }
                return marker.countRate
            }
        }
    }
}

