import GoogleMaps
import UIKit
import FactoryKit
import Combine

final class TrackMapViewController: UIViewController {

    @Injected(\.locationManager) private var locationManager

    enum StartPosition {
        case userLocation
        case markers(GMSCoordinateBounds)
    }

    private static let cachedMapStyle: GMSMapStyle? = {
        guard let styleURL = Bundle.main.url(forResource: "map_style", withExtension: "json") else {
            Log.error("Unable to find style.json")
            return nil
        }
        do {
            return try GMSMapStyle(contentsOfFileURL: styleURL)
        } catch {
            Log.error("One or more of the map styles failed to load. \(error)")
            return nil
        }
    }()

    let startPostion: StartPosition
    let map: GMSMapView

    private var locationCancel: AnyCancellable?

    init(startPostion: StartPosition, delegate: GMSMapViewDelegate?) {
        self.startPostion = startPostion
        let options = GMSMapViewOptions()
        options.backgroundColor = UIColor(.dark06)
        let map: GMSMapView = GMSMapView(options: options)
        map.mapStyle = Self.cachedMapStyle

        map.isMyLocationEnabled = true
        map.isUserInteractionEnabled = true

        self.map = map

        super.init(nibName: nil, bundle: nil)

        /// Позиционирование
        switch startPostion {
        case .userLocation:
            locationCancel = locationManager.$lastKnownLocation
                .compactMap { $0?.coordinate }
                .first()
                .receive(on: DispatchQueue.main)
                .sink { coordinate in
                    map.camera = GMSCameraPosition(target: coordinate, zoom: TrackMapViewControllerBridge.Consts.defaultZoomLevel)
                }
            self.view = map
        case .markers(let gMSCoordinateBounds):
            map.translatesAutoresizingMaskIntoConstraints = false
            var bounds = gMSCoordinateBounds
            if !bounds.isValid {
                if let location = locationManager.lastKnownLocation {
                    bounds = bounds.includingCoordinate(location.coordinate)
                }
            }
            map.setMinZoom(2, maxZoom: 16)
            let update = GMSCameraUpdate.fit(bounds)
            map.moveCamera(update)
        }
        map.delegate = delegate
    }

    required init?(coder: NSCoder) {
        loggedFatalError("init(coder:) has not been implemented")
    }

    override func viewDidLoad() {
        super.viewDidLoad()
        /// ВНИМАНИЕ! Баг у Google Maps, иногда позиционирование идет в левом верхнем углу при использовании карты в шторке
        /// После исправления SDK можно сделать Lazy инициализацию или вернуться к использованию TrackMapView напрямую
        switch startPostion {
        case .markers:
            DispatchQueue.main.async {
                self.view.addSubview(self.map)

                NSLayoutConstraint.activate([
                    self.map.leadingAnchor.constraint(equalTo: self.view.leadingAnchor),
                    self.map.topAnchor.constraint(equalTo: self.view.topAnchor),
                    self.map.trailingAnchor.constraint(equalTo: self.view.trailingAnchor),
                    self.map.bottomAnchor.constraint(equalTo: self.view.bottomAnchor)
                ])
            }
        default:
            break
        }
    }
}

