import Foundation
import Observation
import CoreLocation

@Observable
final class TrackMarker: Identifiable, Hashable {
    /// id базы данных
    let id: String
    /// id  трэка
    var trackId: String
    /// Ширина
    let latitude: Double
    /// Долгота
    let longitude: Double
    /// Точность
    let accuarcy: Double?
    /// Время
    let timestamp: Int
    /// Скорость счёта
    var countRate: Float
    /// Мощность дозы
    var doseRate: Float

    /// Флаг указывающий что маркер обновлен актуальным значением
    @ObservationIgnored
    var valuesUpdated: Bool

    /// Комментарий
    var comment: String?

    /// Проверка пустой точки
    @ObservationIgnored
    var isEmpty: Bool {
        countRate == 0 && doseRate == 0
    }

    /// Координаты точки
    @ObservationIgnored
    var coordinate: CLLocationCoordinate2D {
        CLLocationCoordinate2D(latitude: latitude, longitude: longitude)
    }

    init(
        id: String,
        trackId: String,
        latitude: Double,
        longitude: Double,
        accuarcy: Double?,
        timestamp: Int,
        countRate: Float,
        doseRate: Float,
        valuesUpdated: Bool,
        comment: String?
    ) {
        self.id = id
        self.trackId = trackId
        self.latitude = latitude
        self.longitude = longitude
        self.accuarcy = accuarcy
        self.timestamp = timestamp
        self.countRate = countRate
        self.doseRate = doseRate
        self.valuesUpdated = valuesUpdated
        self.comment = comment
    }

    static func == (lhs: TrackMarker, rhs: TrackMarker) -> Bool {
        lhs.id == rhs.id
    }

    func hash(into hasher: inout Hasher) {
        hasher.combine(id)
    }
}

extension TrackMarker: Encodable {
    private enum CodingKeys: String, CodingKey {
        case lat
        case lon
        case date
        case countRate
        case doseRate
        case acc
        case comment
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(Decimal(string: String(format: "%.6f", latitude)), forKey: .lat)
        try container.encode(Decimal(string: String(format: "%.6f", longitude)), forKey: .lon)
        try container.encode(timestamp / 1000, forKey: .date)
        try container.encode(Decimal(string: String(format: "%.2f", countRate)), forKey: .countRate)
        try container.encode(Decimal(string: String(format: "%.2f", doseRate * 100)), forKey: .doseRate)
        if let accuarcy {
            try container.encode(Int(accuarcy), forKey: .acc)
        }
        try container.encodeIfPresent(comment, forKey: .comment)
    }
}

extension TrackMarker {
    nonisolated(unsafe) static let mock = TrackMarker(
        id: "test",
        trackId: "trackId",
        latitude: 1,
        longitude: 1,
        accuarcy: 1,
        timestamp: 1,
        countRate: 1,
        doseRate: 1,
        valuesUpdated: false,
        comment: nil
    )
}

