//
//  TrackView.swift
//  Radiacode
//
//  Created by Matvey Kozin on 28.10.2023.
//

import SwiftUI

struct TrackView<MainActionView: View>: View {

    var track: Track?
    @Binding var optionsPresented: Bool
    @Binding var valuesOption: TrackScreenOptions.Values
    @Binding var showBottomInfo: Bool

    let startPosition: TrackMapViewControllerBridge.StartPosition

    @ViewBuilder var mainActionView: MainActionView

    @State private var bottomSheetInfoExpanded = true
    @State private var navigateToMyLocation = false
    @State private var selectedMarker: TrackMarker?
    @State private var bottomSheetVisibleHeight: CGFloat = 20
    @State private var didAppear = false
    @State private var bottomSheetKey = UUID()

    var body: some View {
        ZStack(alignment: .bottomLeading) {
            TrackMapViewControllerBridge(
                markers: track?.markers,
                selectedMarker: $selectedMarker,
                navigateToMyLocation: $navigateToMyLocation,
                valuesOption: $valuesOption,
                startPosition: startPosition
            )
            .padding(.bottom, -60) // To hide "Google"
            .onChange(of: selectedMarker) { _, newValue in
                if newValue != nil, bottomSheetInfoExpanded {
                    withAnimation {
                        bottomSheetInfoExpanded = false
                    }
                }
            }
            .onChange(of: track) { oldValue, newValue in
                if newValue != oldValue {
                    selectedMarker = nil
                }
            }
            .onChange(of: showBottomInfo) { _, showBottom in
                if showBottom {
                    bottomSheetKey = UUID()
                    bottomSheetInfoExpanded = true
                } else {
                    withAnimation(BottomSheetConsts.animation) {
                        bottomSheetVisibleHeight = 20
                    }
                }
            }
            .onAppear {
                DispatchQueue.main.async {
                    didAppear = true
                }
                bottomSheetInfoExpanded = startPosition == .userLocation
            }
            .overlay {
                VStack {
                    HStack(alignment: .bottom) {
                        VStack {
                            ZStack(alignment: .leading) {
                                mainActionView
                            }
                        }
                        Spacer()
                        VStack {
                            Spacer()
                            Button {
                                navigateToMyLocation = true
                            } label: {
                                Image(systemName: "location.fill")
                            }
                            .buttonStyle(.circle(.gray))

                            Button {
                                optionsPresented = true
                            } label: {
                                Image(systemName: "ellipsis")
                                    .rotationEffect(.degrees(90))
                            }
                            .buttonStyle(.circle(.gray))
                        }
                        .foregroundStyle(.white)
                    }
                    .padding(.leading, 16)
                    .padding(.trailing, 8)
                }
                .padding(.bottom, bottomSheetVisibleHeight + 8)
            }
            .overlay(alignment: .bottom) {
                if showBottomInfo, let track {
                    BottomSheetView(
                        mode: .detents,
                        parentAppeared: $didAppear,
                        isExpanded: $bottomSheetInfoExpanded,
                        offsetHeight: $bottomSheetVisibleHeight
                    ) {
                        TrackInfoView(track: track)
                            .padding(.top, 24)
                            .liquidPadding(.horizontal, 10)
                    }
                    .id(bottomSheetKey)
                    .transition(.opacity.combined(with: .move(edge: .bottom)))
                }
            }
            VStack {
                Spacer()
                if let selectedMarker, let track {
                    TrackMarkerInfoView(track: track, marker: selectedMarker) {
                        self.selectedMarker = nil
                    }
                    .transition(.move(edge: .bottom))
                }
            }
            .animation(BottomSheetConsts.animation, value: selectedMarker)
        }
    }
}

#Preview {
    TrackView(
        track: .mockActive,
        optionsPresented: .constant(true),
        valuesOption: .constant(.count),
        showBottomInfo: .constant(true),
        startPosition: .markers
    ) {
        EmptyView()
    }
}

