                    HStack {
                        Spacer()
                        switch activeTrack.state {
                        case .notStarted:
                            Button(.Base.start, systemImage: "play") {
                                analyticsEngine.reportEvent(TrackAnalyticsEvent.widgetStartClick)
                                Task {
                                   await activeTrack.startWatch()
                                }
                            }
                            .buttonStyle(.control(.white, scale: .compact))
                            .disabled(!activeTrack.deviceIsReady)
                        case .inProgress:
                            Button(activeTrack.secondsElapsed.toFormattedString, systemImage: "pause") {
                                analyticsEngine.reportEvent(TrackAnalyticsEvent.widgetPauseClick)
                                Task {
                                   await activeTrack.pauseWatch()
                                }
                            }
                            .buttonStyle(.control(.grayLight, scale: .compact))

                        case .pause:
                            Button(activeTrack.secondsElapsed.toFormattedString, systemImage: "play") {
                                analyticsEngine.reportEvent(TrackAnalyticsEvent.widgetResumeClick)
                                Task {
                                    await activeTrack.resumeWatch()
                                }
                            }
                            .buttonStyle(.control(.white, scale: .compact))
                            .disabled(!activeTrack.deviceIsReady)
                        }
                    }
                    .padding(.top, 9)
                    .padding(.trailing, 12)
                } else {
                    VStack(alignment: .center) {
